async function makeTempDir(): Promise<string> {
  const dir = await mkdtemp(join(process.cwd(), "tmp-index-store-"));
  tempDirs.push(dir);
  return dir;
}

afterEach(async () => {
  await Promise.all(
    tempDirs.splice(0).map((dir) => rm(dir, { recursive: true, force: true })),
