describe("indexStore", () => {
  it("saves an index as pretty JSON", async () => {
    const dir = await makeTempDir();
    const indexPath = join(dir, "indexes", "repo-index.json");

    await saveIndex(indexPath, "/repo/path", sampleChunks);

    const raw = await readFile(indexPath, "utf8");
    const saved = JSON.parse(raw) as {
      repoPath: string;
      createdAt: number;
      chunkCount: number;
      chunks: EmbeddedChunk[];
    };

    expect(raw).toContain('\n  "repoPath": "/repo/path"');
    expect(saved.repoPath).toBe("/repo/path");
    expect(saved.chunkCount).toBe(sampleChunks.length);
    expect(saved.chunks).toEqual(sampleChunks);
    expect(typeof saved.createdAt).toBe("number");
  });

  it("loads a saved index", async () => {
    const dir = await makeTempDir();
    const indexPath = join(dir, "repo-index.json");

    await saveIndex(indexPath, "/repo/path", sampleChunks);
    const loaded = await loadIndex(indexPath);

    expect(loaded).not.toBeNull();
    expect(loaded?.repoPath).toBe("/repo/path");
    expect(loaded?.chunkCount).toBe(sampleChunks.length);
    expect(loaded?.chunks).toEqual(sampleChunks);
    expect(typeof loaded?.createdAt).toBe("number");
  });

  it("returns null when the index file does not exist", async () => {
    const dir = await makeTempDir();
    const indexPath = join(dir, "missing.json");

    await expect(loadIndex(indexPath)).resolves.toBeNull();
  });

  it("returns null when the index file contains invalid JSON", async () => {
    const dir = await makeTempDir();
    const indexPath = join(dir, "invalid.json");

    await writeFile(indexPath, "{not-valid-json}", "utf8");

    await expect(loadIndex(indexPath)).resolves.toBeNull();
  });
});

import { mkdir, readFile, writeFile } from "fs/promises";
import { dirname } from "path";

import type { EmbeddedChunk } from "./embedChunks";

export interface SavedIndex {
  repoPath: string;
  createdAt: number;
  chunkCount: number;
  chunks: EmbeddedChunk[];
}

export async function saveIndex(
  indexPath: string,
  repoPath: string,
  chunks: EmbeddedChunk[],
): Promise<void> {
  const data: SavedIndex = {
    repoPath,
    createdAt: Date.now(),
    chunkCount: chunks.length,
    chunks,
  };

  await mkdir(dirname(indexPath), { recursive: true });
  await writeFile(indexPath, JSON.stringify(data, null, 2), "utf8");
}

export async function loadIndex(indexPath: string): Promise<SavedIndex | null> {
  try {
    const raw = await readFile(indexPath, "utf8");
    return JSON.parse(raw) as SavedIndex;
  } catch {
    return null;
  }
}

import { getLmStudioConfig } from "@/lib/config";

export type EmbedTextFn = (text: string) => Promise<number[]>;

interface EmbeddingResponse {
  data?: Array<{
    embedding?: number[];
  }>;
  error?: {
    message?: string;
  };
}

function normalizeBaseUrl(baseUrl: string): string {
  return baseUrl.endsWith("/") ? baseUrl.slice(0, -1) : baseUrl;
}

async function readErrorMessage(response: Response): Promise<string> {
  try {
    const data = (await response.json()) as EmbeddingResponse;
    return data.error?.message || `LM Studio request failed with status ${response.status}.`;
  } catch {
    return `LM Studio request failed with status ${response.status}.`;
  }
}

export async function embedText(text: string): Promise<number[]> {
  const { baseUrl, embeddingModel, apiKey } = getLmStudioConfig();
  const response = await fetch(`${normalizeBaseUrl(baseUrl)}/embeddings`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      ...(apiKey ? { Authorization: `Bearer ${apiKey}` } : {}),
    },
    body: JSON.stringify({
      model: embeddingModel,
      input: text,
    }),
  });

  if (!response.ok) {
    throw new Error(await readErrorMessage(response));
  }

  const data = (await response.json()) as EmbeddingResponse;
  const embedding = data.data?.[0]?.embedding;

  if (!Array.isArray(embedding) || embedding.length === 0) {
    throw new Error(`LM Studio returned an empty embedding for model "${embeddingModel}".`);
  }

  return embedding;
}

import { getLmStudioConfig } from "@/lib/config";
export { embedText } from "./embedder";

export interface GenerateAnswerInput {
  systemPrompt: string;
  userPrompt: string;
}

interface ChatCompletionResponse {
  choices?: Array<{
    message?: {
      content?: ChatMessageContent;
    };
  }>;
  error?: {
    message?: string;
  };
}

type ChatMessageContent =
  | string
  | Array<{
      type?: string;
      text?: string;
    }>
  | undefined;

function normalizeBaseUrl(baseUrl: string): string {
  return baseUrl.endsWith("/") ? baseUrl.slice(0, -1) : baseUrl;
}

function readMessageContent(content: ChatMessageContent): string {
  if (typeof content === "string") {
    return content.trim();
  }

  if (Array.isArray(content)) {
    return content
      .map((part) => (part.type === "text" ? part.text ?? "" : ""))
      .join("\n")
      .trim();
  }

  return "";
}

async function readErrorMessage(response: Response): Promise<string> {
  try {
    const data = (await response.json()) as ChatCompletionResponse;
    return data.error?.message || `LM Studio request failed with status ${response.status}.`;
  } catch {
    return `LM Studio request failed with status ${response.status}.`;
  }
}

export async function generateAnswer({
  systemPrompt,
  userPrompt,
}: GenerateAnswerInput): Promise<string> {
  const { baseUrl, model, apiKey } = getLmStudioConfig();
  const response = await fetch(`${normalizeBaseUrl(baseUrl)}/chat/completions`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      ...(apiKey ? { Authorization: `Bearer ${apiKey}` } : {}),
    },
    body: JSON.stringify({
      model,
      temperature: 0.1,
      messages: [
        {
          role: "system",
          content: systemPrompt,
        },
        {
          role: "user",
          content: userPrompt,
        },
      ],
    }),
  });

  if (!response.ok) {
    throw new Error(await readErrorMessage(response));
  }

  const data = (await response.json()) as ChatCompletionResponse;
  const content = readMessageContent(data.choices?.[0]?.message?.content);

  if (!content) {
    throw new Error(`LM Studio returned an empty response for model "${model}".`);
  }

  return content;
}

